changeSet.sql:
-- Создаем временную колонку для хранения зашифрованных номеров
ALTER TABLE cards ADD COLUMN IF NOT EXISTS encrypted_card_number VARCHAR(255);

-- Комментарий: существующие номера будут зашифрованы Java-кодом
COMMENT ON COLUMN cards.encrypted_card_number IS 'Зашифрованный номер карты';
